#include <iostream>
#include <string>
using namespace std;

class Counter {
private:
    int count;      // hidden
    int maxCount;   // hidden

public:
    Counter(int max) : count(0), maxCount(max) {}

    void increment() {
        if (count < maxCount) count++;
    }

    void decrement() {
        if (count > 0) count--;
    }

    int getCount()  const { return count; }
    bool isFull()   const { return count == maxCount; }
};

int main() {
    Counter c(5);
    c.increment(); c.increment(); c.increment();
    c.increment(); c.increment();
    c.increment();  // no effect — at max

    cout << c.getCount() << endl;
    cout << boolalpha << c.isFull() << endl;
    // c.count = 99;  // compile error!

    return 0;
}

#include <iostream>
#include <string>
#include <stdexcept>
using namespace std;

class Person {
    string name;
    int age;

public:
    Person(string name, int age) : name(name) {
        setAge(age);  // validate even in constructor
    }

    string getName() const { return name; }
    int    getAge()  const { return age; }

    void setAge(int age) {
        if (age < 0 || age > 150)
            throw invalid_argument("Invalid age: " + to_string(age));
        this->age = age;
    }
};

int main() {
    Person p("Alice", 25);
    cout << p.getName() << " is " << p.getAge() << endl;

    p.setAge(26);
    cout << p.getAge() << endl;

    try {
        p.setAge(-5);
    } catch (const invalid_argument& e) {
        cout << "Error: " << e.what() << endl;
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Rectangle {
    double width, height;

public:
    Rectangle(double w, double h) : width(w), height(h) {}

    double area()      const { return width * height; }
    double perimeter() const { return 2 * (width + height); }

    void scale(double factor) {   // non-const: modifies object
        width  *= factor;
        height *= factor;
    }

    void print() const {          // const: just reads
        cout << width << " x " << height << endl;
    }
};

int main() {
    const Rectangle r(4, 6);  // const object!
    r.print();
    cout << r.area() << endl;
    // r.scale(2);  // compile error — can't call non-const on const object

    Rectangle r2(3, 5);
    r2.scale(2);  // OK — r2 is not const
    r2.print();

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Temperature {
    double celsius;

public:
    Temperature(double c) : celsius(c) {}

    double toCelsius()    const { return celsius; }
    double toFahrenheit() const { return celsius * 9.0/5.0 + 32; }
    double toKelvin()     const { return celsius + 273.15; }

    // friend: operator<< needs access to private celsius
    friend ostream& operator<<(ostream& os, const Temperature& t) {
        return os << t.celsius << "°C";
    }

    bool operator<(const Temperature& other) const {
        return celsius < other.celsius;
    }
};

int main() {
    Temperature boiling(100), freezing(0), body(37);

    cout << boiling << " = " << boiling.toFahrenheit() << "°F" << endl;
    cout << body    << " = " << body.toKelvin() << "K" << endl;
    cout << boolalpha << (freezing < body) << endl;

    return 0;
}
